class Solution:
    def maxScoreIndices(self, nums):
        n = len(nums)
        scores = []
        for i in range(n + 1):
            zeros = nums[:i].count(0)
            ones = nums[i:].count(1)
            scores.append(zeros + ones)
        best = max(scores)
        return [i for i, s in enumerate(scores) if s == best]

