class Solution:
    def maxScoreIndices(self, nums):
        n = len(nums)
        total_ones = sum(nums)
        zeros_left = 0
        ones_right = total_ones
        best = -1
        result = []
        for i in range(n + 1):
            score = zeros_left + ones_right
            if score > best:
                best = score
                result = [i]
            elif score == best:
                result.append(i)
            if i < n:
                if nums[i] == 0:
                    zeros_left += 1
                else:
                    ones_right -= 1
        return result

