var maxScoreIndices = function(nums) {
    const n = nums.length;
    let totalOnes = 0;
    for (const x of nums) totalOnes += x;
    let zerosLeft = 0;
    let onesRight = totalOnes;
    let best = -1;
    let result = [];
    for (let i = 0; i <= n; i++) {
        const score = zerosLeft + onesRight;
        if (score > best) {
            best = score;
            result = [i];
        } else if (score === best) {
            result.push(i);
        }
        if (i < n) {
            if (nums[i] === 0) zerosLeft++;
            else onesRight--;
        }
    }
    return result;
};
